"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[6802],{3107(e,t,s){s.r(t),s.d(t,{assets:()=>r,contentTitle:()=>h,default:()=>d,frontMatter:()=>a,metadata:()=>o,toc:()=>l});const o=JSON.parse('{"id":"stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-23","title":"Discourses \u2014 Book 2, Chapter 23","description":"Book 2 \u2014 Chapter 23","source":"@site/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-23.md","sourceDirName":"stoicism/epictetus/discourses/book-2","slug":"/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-23","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-23","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":24,"frontMatter":{"sidebar_position":24,"title":"Discourses \u2014 Book 2, Chapter 23","sidebar_label":"Book 2, Ch. 23"},"sidebar":"philosophersSidebar","previous":{"title":"Book 2, Ch. 22","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-22"},"next":{"title":"Book 2, Ch. 24","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-24"}}');var i=s(4848),n=s(8453);const a={sidebar_position:24,title:"Discourses \u2014 Book 2, Chapter 23",sidebar_label:"Book 2, Ch. 23"},h="Discourses",r={},l=[{value:"Book 2 \u2014 Chapter 23",id:"book-2--chapter-23",level:2},{value:"On The Faculty Of Expression",id:"on-the-faculty-of-expression",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function u(e){const t={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,n.R)(),...e.components},{Details:s}=t;return s||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,i.jsxs)(i.Fragment,{children:[(0,i.jsxs)("div",{style:{textAlign:"center"},children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"discourses",children:"Discourses"})}),(0,i.jsx)(t.h2,{id:"book-2--chapter-23",children:"Book 2 \u2014 Chapter 23"}),(0,i.jsx)(t.h3,{id:"on-the-faculty-of-expression",children:"On The Faculty Of Expression"})]}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,i.jsxs)(s,{open:!0,children:[(0,i.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,i.jsx)(t.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,i.jsx)(t.p,{children:"A careful argument against two opposite errors: dismissing eloquence as worthless, and treating it as the highest thing. It's neither. Expression is a genuine gift from God \u2014 like vision or hearing \u2014 and to deny its value is ungrateful and cowardly. But the will is the faculty that governs all others, including speech. It decides when to speak, what to say, and whether speaking at all is appropriate. Expression serves the will; the will does not serve expression."}),(0,i.jsx)(t.p,{children:"The inn metaphor is the chapter's best image: rhetoric, syllogisms, stylistic elegance \u2014 these are fine inns on the road to the actual destination. The problem is when travelers stop at the inn and forget where they were going. Many students get caught by style, others by logical puzzles, others by the pleasure of the school itself, and there they molder like Siren-victims. The purpose was to become capable of handling impressions correctly \u2014 free, unhindered, at peace with the governance of God. That purpose is what counts. Everything else is infrastructure."})]}),"\n",(0,i.jsxs)(s,{open:!0,children:[(0,i.jsx)("summary",{children:"Text"}),(0,i.jsx)(t.h2,{id:"text",children:"Text"}),(0,i.jsx)(t.p,{children:"EVERY one can read a book with the more pleasure and ease the plainer the letters in which it is written. So too every one can listen more easily to discourse which is expressed in becoming and distinguished language. We must therefore not say that the faculty of expression is nothing. To say so is at once irreligious and cowardly; irreligious because it means disparaging God's gifts, just as though one should deny the usefulness of the faculty of vision or hearing or even the faculty of speech. Was it for nothing then that God gave you your eyes? Was it for nothing He mingled with them a spirit  so powerful and cunningly devised, that even from a distance they can fashion the shapes of what they see? And what messenger is so swift and attentive as they? Was it for nothing that He made the intervening air so active and sensitive that vision passes through it as through a tense medium? Was it for nothing that He made light, without the presence of which all the rest would have been useless?"}),(0,i.jsx)(t.p,{children:"Man, be not ungrateful, nor again forget higher things! Give thanks to God for sight and hearing, yes, and for life itself and what is conducive to life--for grain and fruit, for wine and oil; but remember that He has given you another gift superior to all these, the faculty which shall use them, test them, and calculate the value of each. For what is it that pronounces on each of these faculties, and decides their value? Is it the faculty itself, in each case? Did you ever hear the faculty of vision saying anything about itself, or the faculty of hearing? No, these faculties are ordained as ministers and slaves to serve the"}),(0,i.jsx)(t.p,{children:"faculty which deals with impressions. And if you ask what each is worth, whom do you ask? Who answers you? How then can any other faculty be superior to this, which uses the rest as its servants and itself tests each result and pronounces on it? Which of those faculties knows what it is and what it is worth, which of them knows when it ought to be used and when it ought not? What is the faculty that opens and closes the eyes and brings them near some objects and turns them away, at need, from others? Is it the faculty of vision? No, it is the faculty of will. What is it that closes and opens the ears? What is it that makes us curious and questioning, or again unmoved by discourse? Is it the faculty of hearing? It is no other faculty but that of the will."}),(0,i.jsx)(t.p,{children:"I say, when the will sees that all the other faculties which surround it are blind and deaf and are unable to see anything else beyond the very objects for which they are ordained to minister to this faculty and serve it, and this alone has clear sight and surveys the rest and itself and estimates their value, is it likely to pronounce that any other faculty but itself is the highest? What is the function of the eye, when opened, but to see? But what is it tells us whether we ought to look at a man's wife or how? The faculty of will. What tells us whether we ought to believe or disbelieve what we are told, and if we believe whether we are to be excited or not? Is it not the faculty of will? This faculty of eloquence I spoke of, if such special faculty there be, concerned with the framing of fair phrases, does no more than construct and adorn phrases, when there is an occasion for discourse, just as hairdressers arrange and adorn the hair. But whether it is better to speak or be silent, and to speak in this way or that, and whether it is proper or improper--in a word, to decide the occasion and the use for each discourse, all these are questions for one faculty only, that of the will. Would you have it come forward and pronounce against itself?"}),(0,i.jsx)(t.p,{children:"'But', says the objector, 'what if the matter stands thus, what if that which ministers can be superior to that which it serves, the horse to the horseman, the hound to the hunter, the lyre to him that plays it, the servants to the king they serve?' The answer is: What is it that uses other things? The will. What is it that attends to everything? The will. What is it that destroys the whole man, now by starvation, now by a halter, now by a headlong fall? The will. Is there then anything stronger in men than this? Nay, how can things that are subject to hindrance be stronger than that which is unhindered? What has power to hinder the faculty of vision? Will and events beyond the will. The faculty of hearing and that of speech are subject to the same hindrance. But what can hinder the will? Nothing beyond the will, only the perversion of the will itself. Therefore vice or virtue resides in this alone. Yet being so mighty a faculty, ordained to rule all the rest, you would have it come"}),(0,i.jsx)(t.p,{children:"forward and tell us that the flesh is of all things most excellent. Why, if the flesh itself asserted that it was the most excellent of things, one would not tolerate it even then. But as it is, Epicurus, what is the faculty that pronounces this judgement? Is it the faculty which has written on 'The End' or 'Physics' or 'The Standard'? The faculty which made you grow your beard as a philosopher? which wrote in the hour of death 'I am living my last day and that a blessed one'?  Is this faculty flesh or will? Surely it is madness to admit that you have a faculty superior to this. Can you be in truth so blind and deaf?"}),(0,i.jsx)(t.p,{children:"What follows? Do we disparage the other faculties? God forbid. Do we say that there is no use nor advancement save in the faculty of will? God forbid! That were foolish, irreligious, ungrateful toward God. We are only giving each thing its due. For there is use in an ass, but not so much as in an ox; there is use in a dog, but not so much as in a servant; there is use in a servant, but not so much as in a fellow-citizen; there is use in them too, but not so much as in those who govern them. Yet because other faculties are higher we must not depreciate the use which inferior faculties yield. The faculty of eloquence has its value, but it is not so great as that of the will; but when I say this, let no one suppose that I bid you neglect your manner of speech, any more than I would have you neglect eyes or ears or hands or feet or clothes or shoes."}),(0,i.jsx)(t.p,{children:"But if you ask me, 'What then is the highest of all things,' what am I to say? The faculty of speech? I cannot say that. No, the faculty of will, when it is in the right way. For it is this which controls the faculty of speech and all other faculties small and great. When this is set in the right course, a man becomes good; when it fails, man becomes bad; it is this which makes our fortune bad or good, this which makes us critical of one another or well content; in a word, to ignore this means misery, to attend to it means happiness."}),(0,i.jsx)(t.p,{children:"Yet to do away with the faculty of eloquence and deny its existence is indeed not only ungrateful to those who have given it, but shows a coward's spirit. For he who denies it seems to me to fear that, if there is a faculty of eloquence, we may not be able to despise it. It is just the same with those who deny that there is any difference between beauty and ugliness. What! are we to believe that the sight of Thersites could move men as much as the sight of Achilles, and the sight of Helen no more than the sight of an ordinary woman? No, these are the words of foolish and uneducated persons, who do not know one thing from another, and who fear that if once one becomes aware of such differences, one may be overwhelmed and defeated."}),(0,i.jsx)(t.p,{children:"No, the great thing is this--to leave each in possession of his own faculty, and so leaving him to see the value of the faculty, and to"}),(0,i.jsx)(t.p,{children:"understand what is the highest of all things and to pursue this always, and concentrate your interest on this, counting all other things subordinate to this, yet not failing to attend to them too so far as you may. For even to the eyes you must attend, yet not as though they were the highest, but to these also for the sake of the highest; for the highest will not fulfil its proper nature unless it uses the eyes with reason, and chooses one thing rather than another."}),(0,i.jsx)(t.p,{children:"What then do we see men doing? They are like a man returning to his own country who, finding a good inn on his road, stays on there because it pleases him. Man, you are forgetting your purpose! You were not travelling to this, but through it."}),(0,i.jsx)(t.p,{children:"'Yes, but this is a fine inn.'"}),(0,i.jsx)(t.p,{children:"And how many other fine inns are there, and how many fine meadows? But they are merely to pass through; your purpose is yonder; to return to your country, to relieve your kinsfolk of their fears, to fulfil your own duties as a citizen, to marry, beget children, and hold office in due course. For you have not come into the world to choose your pick of fine places, but to live and move in the place where you were born and appointed to be a citizen. The same principle holds good in what we are discussing. Our road to perfection must needs lie through instruction and the spoken word; and one must purify the will and bring into right order the faculty which deals with impressions; and principles must be communicated in a particular style, with some variety and epigram. But this being so, some people are attracted by the very means they are using and stay where they are, one caught by style, another by syllogisms, a third by variable arguments, and a fourth by some other seductive inn by the way; and there they stay on and moulder away, like those whom the Sirens entertain."}),(0,i.jsx)(t.p,{children:"Man, the purpose set before you was to make yourself capable of dealing with the impressions that you meet as nature orders, so as not to fail in what you will to get, nor to fall into what you will to avoid, never suffering misfortune or bad fortune, free, unhindered, unconstrained, conforming to the governance of God, obeying this, well pleased with this, criticizing none, blaming none, able to say these lines with your whole heart,"}),(0,i.jsx)(t.p,{children:"Lead me, O Zeus, and thou my Destiny."}),(0,i.jsx)(t.p,{children:"[Cleanthes]"}),(0,i.jsx)(t.p,{children:"Having this purpose before you, are you going to stay where you are just because a pretty phrase or certain precepts please you, and choose to make your home there, forgetting what you have left at home, and say, 'These things are fine'? Who says they are not fine? But they are fine as things to pass through, as inns by the way. What prevents you"}),(0,i.jsx)(t.p,{children:"from being unfortunate, though you speak like Demosthenes? Though you can analyse syllogisms like Chrysippus, what prevents you from being wretched, mournful, envious--in a word, bewildered and miserable? Nothing prevents you. Do you see then that these were inns of no value; and the goal set before you was different? Certain persons when I say this think I am disparaging the study of rhetoric or of principles. No, I am not depreciating that, but only the tendency to dwell unceasingly on such matters and to set your hopes on them. If any man does his hearers harm by bringing this truth home to them, count me among those who do this harm. But when I see that what is highest and most sovereign is something different, I cannot say that it is what it is not in order to gratify you."})]})]})}function d(e={}){const{wrapper:t}={...(0,n.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(u,{...e})}):u(e)}},8453(e,t,s){s.d(t,{R:()=>a,x:()=>h});var o=s(6540);const i={},n=o.createContext(i);function a(e){const t=o.useContext(n);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function h(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),o.createElement(n.Provider,{value:t},e.children)}}}]);